import json
import os
import re
import subprocess

AC_UID = "499b24cbd8017b00"
AC_TYPE = "data"


def _repo_root():
    return subprocess.check_output(
        ["git", "rev-parse", "--show-toplevel"], text=True
    ).strip()


def _read(rel):
    with open(os.path.join(_repo_root(), rel), encoding="utf-8") as f:
        return f.read()


def _live_counts():
    root = _repo_root()
    with open(os.path.join(root, "settings.json"), encoding="utf-8") as f:
        s = json.load(f)
    hooks = s.get("hooks", {})
    wired = 0
    distinct = set()
    for _ev, matchers in hooks.items():
        for m in matchers:
            for h in m.get("hooks", []):
                wired += 1
                for bn in re.findall(r"hooks/[\w./-]+\.(?:py|sh)", h.get("command", "")):
                    distinct.add(bn.split("/")[-1])
    perms = s.get("permissions", {})
    return {
        "wired": wired,
        "distinct": len(distinct),
        "allow": len(perms.get("allow", [])),
        "deny": len(perms.get("deny", [])),
        "ask": len(perms.get("ask", [])),
    }


def test_AC3():
    """
    GIVEN: ARCHITECTURE.md after the fix
    WHEN:  its counts are compared to a fresh recomputation from settings.json
    THEN:  wired-entries, distinct-files, on-disk, per-event, and permissions numbers equal the live recomputed values and match the README badge; no false 'share the same verified counts' claim remains
    """
    live = _live_counts()
    arch = _read("ARCHITECTURE.md")
    readme = _read("README.md")

    # ARCHITECTURE inventory row values must equal live recompute.
    assert re.search(
        r"Hook command entries wired.*?\*\*%d\*\*" % live["wired"], arch
    ), f"ARCHITECTURE wired-entries != live {live['wired']}"
    assert re.search(
        r"Distinct hook files referenced.*?\*\*%d\*\*" % live["distinct"], arch
    ), f"ARCHITECTURE distinct-files != live {live['distinct']}"
    assert re.search(
        r"%d\s*/\s*%d\s*/\s*%d" % (live["allow"], live["deny"], live["ask"]), arch
    ), f"ARCHITECTURE permissions != live {live['allow']}/{live['deny']}/{live['ask']}"

    # README badge must carry the same wired/distinct + perms numbers.
    assert re.search(
        r"%d%%20files%%20%%2F%%20%d%%20wired" % (live["distinct"], live["wired"]), readme
    ), "README hooks badge != live distinct/wired"
    assert re.search(
        r"%d%%20allow%%20%%2F%%20%d%%20deny%%20%%2F%%20%d%%20ask"
        % (live["allow"], live["deny"], live["ask"]),
        readme,
    ), "README permissions badge != live allow/deny/ask"

    # No false parity claim ('share the same verified component counts').
    assert "share the same verified component counts" not in arch, (
        "ARCHITECTURE still carries the false parity claim"
    )

